@layer reset, tokens, layout, components, utilities;

@property --progress-color {
  syntax: '<color>';
  initial-value: #33ff33;
  inherits: false;
}

@layer tokens {
  :root {
    --ds-bg: rgb(10, 10, 26);
    --ds-text: rgb(51, 255, 51);
    --ds-accent: rgb(255, 102, 0);
    --ds-surface: rgb(26, 26, 46);
    --ds-border: rgb(51, 51, 102);
    --ds-font: 'IBM Plex Mono', monospace;
    --ds-radius: 4px;
    --ds-space-sm: 8px;
    --ds-space-md: 16px;
    --ds-space-lg: 24px;
  }
}

@layer reset {
  *, *::before, *::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }
}

@layer layout {
  .ds-app {
    min-height: 100vh;
    background-color: var(--ds-bg);
    color: var(--ds-text);
    font-family: var(--ds-font);
    display: grid;
    grid-template-rows: auto 1fr;
  }

  .ds-content {
    padding: var(--ds-space-lg);
  }
}

@layer components {
  .ds-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: var(--ds-space-md) var(--ds-space-lg);
    background-color: var(--ds-surface);
    border-bottom: 1px solid var(--ds-border);

    & .ds-logo {
      font-size: 18px;
      color: var(--ds-accent);
    }
  }

  .ds-nav {
    display: flex;
    gap: var(--ds-space-sm);

    & .ds-nav-link {
      color: var(--ds-text);
      text-decoration: none;
      padding: var(--ds-space-sm) var(--ds-space-md);
      border-radius: var(--ds-radius);
      opacity: 0.6;

      &:hover {
        opacity: 1;
        background-color: rgba(51, 255, 51, 0.1);
      }

      &.ds-nav-link--active {
        opacity: 1;
        background-color: rgba(51, 255, 51, 0.15);
      }
    }
  }

  .ds-challenge-card {
    background-color: var(--ds-surface);
    border: 1px solid var(--ds-border);
    border-radius: var(--ds-radius);
    padding: var(--ds-space-lg);
  }

  .ds-card-header {
    display: flex;
    justify-content: space-between;
    margin-bottom: var(--ds-space-md);
  }

  .ds-difficulty {
    color: var(--ds-accent);
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 1px;
  }

  .ds-stars {
    color: rgb(255, 215, 0);
  }

  .ds-card-title {
    font-size: 20px;
    margin-bottom: var(--ds-space-sm);
  }

  .ds-card-desc {
    opacity: 0.7;
    line-height: 1.5;
    margin-bottom: var(--ds-space-md);
  }

  .ds-progress-bar {
    height: 8px;
    background-color: var(--ds-bg);
    border-radius: 4px;
    overflow: hidden;
  }

  .ds-progress-fill {
    height: 100%;
    width: calc(var(--progress) * 100%);
    background-color: var(--ds-text);
    border-radius: 4px;
    transition: width 0.5s ease, --progress-color 0.5s;
  }

  @container (max-width: 400px) {
    .ds-challenge-card {
      padding: var(--ds-space-md);
    }
    .ds-card-title {
      font-size: 16px;
    }
  }
}

